<?php /** * Plugin Name: Auto SEO Keyword Linker * Description: High-performance keyword-to-link transformer. Features CSV Import/Export, Smart Scanner, Unicode support, and Sitewide Blacklisting. * Version: 1.3.3 * License: GPL-2.0-or-later */ if ( ! defined( 'ABSPATH' ) ) exit; define( 'AKL_OPT', 'akl_settings' ); add_action( 'admin_menu', function() { add_options_page( 'Keyword Links', 'Keyword Links', 'manage_options', 'auto-keyword-linker', 'akl_page' ); }); add_action( 'admin_init', function() { register_setting( 'akl_options', AKL_OPT, 'akl_sanitize' ); add_settings_section( 'main', 'Configuration', '__return_false', 'auto-keyword-linker' ); add_settings_field( 'pairs', 'Keywords & URLs', 'akl_f_pairs', 'auto-keyword-linker', 'main' ); add_settings_field( 'max', 'Max Links Per Page', 'akl_f_max', 'auto-keyword-linker', 'main' ); add_settings_field( 'ext', 'SEO & Behavior', 'akl_f_ext', 'auto-keyword-linker', 'main' ); add_settings_field( 'blacklist', 'Sitewide Blacklist', 'akl_f_blacklist', 'auto-keyword-linker', 'main' ); }); function akl_f_pairs() { $o = get_option( AKL_OPT ); printf( '<textarea name="%s[pairs]" rows="10" class="large-text code" placeholder="keyword|https://link.com">%s</textarea>', AKL_OPT, esc_textarea( $o['pairs'] ?? '' ) ); } function akl_f_max() { $o = get_option( AKL_OPT ); printf( '<input type="number" name="%s[max]" value="%d" min="1" max="50">', AKL_OPT, absint( $o['max'] ?? 1 ) ); } function akl_f_ext() { $o = get_option( AKL_OPT ); printf( '<label><input type="checkbox" name="%1$s[tab]" value="1" %2$s> New Tab</label> &nbsp; ', AKL_OPT, checked( !empty($o['tab']), true, false ) ); printf( '<label><input type="checkbox" name="%1$s[nf]" value="1" %2$s> Nofollow</label>', AKL_OPT, checked( !empty($o['nf']), true, false ) ); } function akl_f_blacklist() { $o = get_option( AKL_OPT ); printf( '<textarea name="%s[bl]" rows="3" class="large-text code" placeholder="Exclude URLs...">%s</textarea>', AKL_OPT, esc_textarea( $o['bl'] ?? '' ) ); } function akl_sanitize( $i ) { return [ 'pairs' => sanitize_textarea_field( $i['pairs'] ), 'bl' => sanitize_textarea_field( $i['bl'] ), 'max' => max( 1, min( 50, absint( $i['max'] ) ) ), 'tab' => !empty($i['tab']) ? 1 : 0, 'nf' => !empty($i['nf']) ? 1 : 0, ]; } add_action( 'admin_init', function() { if ( isset( $_GET['akl_export'] ) && current_user_can( 'manage_options' ) ) { $o = get_option( AKL_OPT ); header( 'Content-Type: text/csv' ); header( 'Content-Disposition: attachment; filename=keywords.csv' ); $out = fopen( 'php://output', 'w' ); fputcsv( $out, ['Keyword', 'URL'] ); foreach ( explode( "\n", $o['pairs'] ) as $l ) { if ( strpos( $l, '|' ) ) fputcsv( $out, explode( '|', trim( $l ), 2 ) ); } exit; } if ( isset( $_POST['akl_import_nonce'] ) && wp_verify_nonce( $_POST['akl_import_nonce'], 'akl_import' ) ) { if ( ! empty( $_FILES['csv']['tmp_name'] ) ) { $h = fopen( $_FILES['csv']['tmp_name'], 'r' ); $new = []; fgetcsv( $h ); while ( ($d = fgetcsv( $h )) !== FALSE ) if ( count($d) >= 2 ) $new[] = trim($d[0]) . '|' . esc_url_raw(trim($d[1])); $o = get_option( AKL_OPT ); $o['pairs'] = implode( "\n", array_unique( array_merge( explode( "\n", $o['pairs'] ), $new ) ) ); update_option( AKL_OPT, $o ); } } }); function akl_page() { ?> <div class="wrap"> <h1>Auto SEO Keyword Linker <small>v1.3.3</small></h1> <div style="display: grid; grid-template-columns: 2fr 1fr; gap: 20px;"> <div> <form method="post" action="options.php"> <?php settings_fields( 'akl_options' ); do_settings_sections( 'auto-keyword-linker' ); submit_button(); ?> </form> <div class="card"> <h2>CSV Import/Export</h2> <form method="post" enctype="multipart/form-data" style="margin-bottom:15px;"> <?php wp_nonce_field( 'akl_import', 'akl_import_nonce' ); ?> <input type="file" name="csv" accept=".csv"> <input type="submit" class="button" value="Import & Merge"> </form> <a href="?page=auto-keyword-linker&akl_export=1" class="button button-secondary">Export to CSV</a> </div> </div> <div> <div class="card" style="background: #f9f9f9;"> <h2 style="margin-top:0;">🚀 Pro Features</h2> <ul style="list-style:disc; margin-left:15px;"> <li>Conditional Category Logic</li> <li>Click Performance Stats</li> <li>Custom Link Titles</li> <li>Advanced Targeting rules</li> </ul> </div> <div class="card"> <h3>Smart Scanner</h3> <button type="button" class="button" id="akl-scan">Find Opportunities</button> <div id="akl-res" style="margin-top:10px;"></div> </div> </div> </div> </div> <script> jQuery(function($){ $('#akl-scan').click(function(){ var b = $(this); b.prop('disabled',true).text('Scanning...'); $.post(ajaxurl, { action: 'akl_scan', nonce: '<?php echo wp_create_nonce("akl_scan"); ?>' }, function(r){ if(r.success && r.data.length){ let h = '<table class="widefat"><thead><tr><th>Keyword</th><th>Target</th></tr></thead><tbody>'; r.data.forEach(i => h += <tr><td>${i.k}</td><td><small>${i.u}</small></td></tr>); $('#akl-res').html(h+'</tbody></table>'); } else $('#akl-res').text('No suggestions.'); b.prop('disabled',false).text('Find Opportunities'); }); }); }); </script> <?php } ## Reminder Add notes... add_action( 'wp_ajax_akl_scan', function() { check_ajax_referer( 'akl_scan', 'nonce' ); $posts = get_posts( ['numberposts' => 20, 'post_status' => 'publish'] ); $out = []; foreach ( $posts as $p ) { $w = explode( ' ', wp_strip_all_tags( strip_shortcodes( $p->post_content ) ) ); for ( $i = 0; $i < count($w)-2; $i++ ) { $ph = trim($w[$i].' '.$w[$i+1].' '.$w[$i+2]); if ( strlen($ph) > 12 ) $out[] = ['k' => $ph, 'u' => get_permalink($p->ID)]; } } wp_send_json_success( array_slice($out, 0, 10) ); }); add_filter( 'the_content', function( $c ) { if ( is_admin() || strpos($c, '') !== false ) return $c; $o = get_option( AKL_OPT ); if ( empty($o['pairs']) ) return $c; if ( !empty($o['bl']) ) { $cur = (is_ssl()?'https://':'http://').$_SERVER['HTTP_HOST'].$_SERVER['REQUEST_URI']; foreach(explode("\n", $o['bl']) as $b) if(trim($b) && strpos($cur, trim($b)) !== false) return $c; } $prs = []; foreach ( explode( "\n", $o['pairs'] ) as $l ) if ( strpos($l, '|') ) { list($k, $u) = explode('|', $l, 2); $prs[] = ['k' => trim($k), 'u' => trim($u)]; } usort( $prs, function($a, $b) { return strlen($b['k']) <=> strlen($a['k']); } ); $limit = (int) ($o['max'] ?? 1); $site = home_url(); $counts = []; $pts = preg_split( '#(<[^>]*>)#', $c, -1, PREG_SPLIT_DELIM_CAPTURE | PREG_SPLIT_NO_EMPTY ); $res = ''; $skip = false; foreach ( $pts as $p ) { if ( $p[0] === '<' ) { if ( preg_match( '#^<(h[1-6]|a|code|pre|script)\b#i', $p ) ) $skip = true; if ( preg_match( '#^</(h[1-6]|a|code|pre|script)>#i', $p ) ) $skip = false; $res .= $p; continue; } if ( $skip ) { $res .= $p; continue; } foreach ( $prs as $item ) { $key_low = strtolower($item['k']); if ( ($counts[$key_low] ?? 0) >= $limit ) continue; $p = preg_replace_callback( '#(?<!\pL)'.preg_quote($item['k'], '#').'(?!\pL)#iu', function($m) use (&$counts, $key_low, $limit, $item, $site, $o) { if ( ($counts[$key_low] ?? 0) >= $limit ) return $m[0]; $counts[$key_low]++; $a = (strpos($item['u'], $site) === false) ? ((!empty($o['tab'])?' target="_blank"':'').(!empty($o['nf'])?' rel="nofollow noopener"':'')) : ''; return '<a href="'.esc_url($item['u']).'"'.$a.'>'.$m[0].'</a>'; }, $p ); } $res .= $p; } return $res; }, 20 );
